class DashboardScreen extends ConsumerWidget{const DashboardScreen({super.key});@override Widget build(BuildContext context,WidgetRef ref){final user=ref.watch(currentUserProvider);final sync=ref.watch(syncStatusProvider);final cards=[('Spese quotidiane',AppColors.daily,Icons.receipt_long,'/daily'),('Abbonamenti',AppColors.subscription,Icons.autorenew,'/subscriptions'),('Rate',AppColors.installment,Icons.credit_card,'/installments'),('Veicolo',AppColors.vehicle,Icons.directions_car,'/vehicle')];return Scaffold(appBar:AppBar(title:Column(crossAxisAlignment:CrossAxisAlignment.start,children:[Text('Ciao, ${user?.displayName??'!'}!'),Text(DateFormat.yMMMMd('it').format(DateTime.now()),style:Theme.of(context).textTheme.bodySmall)]),actions:[Tooltip(message:sync.name,child:Icon(sync==SyncStatus.offline?Icons.cloud_off:sync==SyncStatus.syncing?Icons.sync:Icons.cloud_done)),const SizedBox(width:16)]),body:CustomScrollView(slivers:[SliverPadding(padding:const EdgeInsets.all(16),sliver:SliverList.list(children:[Card(color:Theme.of(context).colorScheme.primaryContainer,child:const Padding(padding:EdgeInsets.all(24),child:Column(crossAxisAlignment:CrossAxisAlignment.start,children:[Text('Spese totali questo mese'),SizedBox(height:8),Text('€ 0,00',style:TextStyle(fontSize:34,fontWeight:FontWeight.bold))])),const SizedBox(height:16)])),SliverPadding(padding:const EdgeInsets.symmetric(horizontal:16),sliver:SliverGrid.builder(gridDelegate:SliverGridDelegateWithFixedCrossAxisCount(crossAxisCount:MediaQuery.sizeOf(context).width>700?4:2,mainAxisExtent:125,crossAxisSpacing:12,mainAxisSpacing:12),itemCount:cards.length,itemBuilder:(c,i){final x=cards[i];return Card(child:InkWell(borderRadius:BorderRadius.circular(16),onTap:()=>context.go(x.$4),child:Padding(padding:const EdgeInsets.all(16),child:Column(crossAxisAlignment:CrossAxisAlignment.start,children:[Icon(x.$3,color:x.$2),const Spacer(),Text(x.$1),Text(euro(0),style:const TextStyle(fontWeight:FontWeight.bold))]))));})),SliverPadding(padding:const EdgeInsets.all(16),sliver:SliverList.list(children:[Text('In scadenza questa settimana',style:Theme.of(context).textTheme.titleLarge),const SizedBox(height:10),const Card(child:ListTile(leading:Icon(Icons.event_available),title:Text('Nessuna scadenza imminente'))),const SizedBox(height:20),Text('Ultime spese',style:Theme.of(context).textTheme.titleLarge),const Card(child:ListTile(leading:Icon(Icons.receipt_long),title:Text('Nessuna transazione')))]))]),floatingActionButton:FloatingActionButton(onPressed:()=>context.go('/daily/add'),child:const Icon(Icons.add)));}}
